import{_ as e,c as a,o as s,aj as l}from"./chunks/framework.VtnL2jmu.js";const p=JSON.parse('{"title":"Nano文本编辑器","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/Nano文本编辑器.md","filePath":"Linux/Nano文本编辑器.md"}'),i={name:"Linux/Nano文本编辑器.md"};function n(d,t,o,r,h,c){return s(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="nano文本编辑器" tabindex="-1">Nano文本编辑器 <a class="header-anchor" href="#nano文本编辑器" aria-label="Permalink to “Nano文本编辑器”">​</a></h1><h2 id="_1-简介" tabindex="-1">1. 简介 <a class="header-anchor" href="#_1-简介" aria-label="Permalink to “1. 简介”">​</a></h2><p>GNU Nano 是一款在 Linux 终端中运行的轻量级文本编辑器。它的设计目标是简单易用，相比 <code>vim</code> 或 <code>emacs</code>，学习曲线非常平缓，非常适合新手编辑配置文件或快速写点东西 。界面底部通常会显示常用的快捷键提示，对新手非常友好 。</p><h2 id="_2-安装-nano" tabindex="-1">2. 安装 Nano <a class="header-anchor" href="#_2-安装-nano" aria-label="Permalink to “2. 安装 Nano”">​</a></h2><p>大多数 Linux 发行版默认预装了 Nano。可以先在终端输入以下命令检查是否已安装：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nano</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>如果系统提示“未找到命令”，可以根据你的 Linux 发行版使用对应的包管理器进行安装：</p><table tabindex="0"><thead><tr><th style="text-align:left;">操作系统 (Linux 发行版)</th><th style="text-align:left;">安装命令</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Ubuntu / Debian</strong></td><td style="text-align:left;"><code>sudo apt update &amp;&amp; sudo apt install nano -y</code></td></tr><tr><td style="text-align:left;"><strong>CentOS / RHEL</strong></td><td style="text-align:left;"><code>sudo yum install nano -y</code></td></tr><tr><td style="text-align:left;"><strong>Fedora</strong></td><td style="text-align:left;"><code>sudo dnf install nano</code></td></tr><tr><td style="text-align:left;"><strong>Arch Linux</strong></td><td style="text-align:left;"><code>sudo pacman -S nano</code></td></tr><tr><td style="text-align:left;"><strong>openSUSE</strong></td><td style="text-align:left;"><code>sudo zypper install nano</code></td></tr></tbody></table><h2 id="_3-基本操作流程" tabindex="-1">3. 基本操作流程 <a class="header-anchor" href="#_3-基本操作流程" aria-label="Permalink to “3. 基本操作流程”">​</a></h2><h3 id="_3-1-打开-新建文件" tabindex="-1">3.1 打开/新建文件 <a class="header-anchor" href="#_3-1-打开-新建文件" aria-label="Permalink to “3.1 打开/新建文件”">​</a></h3><p>在终端中输入 <code>nano</code> 后跟文件名。如果文件不存在，Nano 会自动在当前位置创建一个新文件 。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_first_note.txt</span></span></code></pre></div><h3 id="_3-2-编辑文本" tabindex="-1">3.2 编辑文本 <a class="header-anchor" href="#_3-2-编辑文本" aria-label="Permalink to “3.2 编辑文本”">​</a></h3><p>打开文件后，可以直接开始输入或修改文字。使用键盘的 <strong>方向键（↑↓←→）</strong> 来移动光标。默认情况下<strong>不支持鼠标</strong>操作 。</p><h3 id="_3-3-保存文件" tabindex="-1">3.3 保存文件 <a class="header-anchor" href="#_3-3-保存文件" aria-label="Permalink to “3.3 保存文件”">​</a></h3><p>在 Nano 中，<strong><code>^</code> 符号代表 <code>Ctrl</code> 键</strong>。</p><ul><li>按下 <strong><code>Ctrl + O</code></strong>（WriteOut）：这会触发保存操作。</li><li>按 <strong><code>回车（Enter）</code></strong> 确认文件名。界面底部会提示写入的行数 。</li></ul><h3 id="_3-4-退出编辑器" tabindex="-1">3.4 退出编辑器 <a class="header-anchor" href="#_3-4-退出编辑器" aria-label="Permalink to “3.4 退出编辑器”">​</a></h3><ul><li>按下 <strong><code>Ctrl + X</code></strong>（Exit）：试图退出 Nano。</li><li>如果文件在最后一次保存后有过修改，Nano 会询问是否保存： <ul><li>按 <strong><code>Y</code></strong>（是）：先保存再退出。</li><li>按 <strong><code>N</code></strong>（否）：不保存直接退出。</li><li>按 <strong><code>Ctrl + C</code></strong>：取消退出操作，返回编辑界面 。</li></ul></li></ul><blockquote><p><strong>流程总结</strong>：编辑文件 -&gt; <code>Ctrl + O</code> -&gt; <code>回车</code> -&gt; <code>Ctrl + X</code>。</p></blockquote><h2 id="_4-常用快捷键速查表" tabindex="-1">4. 常用快捷键速查表 <a class="header-anchor" href="#_4-常用快捷键速查表" aria-label="Permalink to “4. 常用快捷键速查表”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">功能分类</th><th style="text-align:left;">快捷键</th><th style="text-align:left;">作用描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>通用</strong></td><td style="text-align:left;"><code>Ctrl + G</code></td><td style="text-align:left;">显示帮助文档（查看所有快捷键列表）</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Ctrl + X</code></td><td style="text-align:left;">退出编辑器</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Ctrl + O</code></td><td style="text-align:left;">保存文件 (Write Out)</td></tr><tr><td style="text-align:left;"><strong>编辑</strong></td><td style="text-align:left;"><code>Ctrl + K</code></td><td style="text-align:left;">剪切当前行（或选中的文本块）</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Ctrl + U</code></td><td style="text-align:left;">粘贴刚才剪切的内容</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Alt + 6</code></td><td style="text-align:left;">复制当前行（或选中的文本块）</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><strong><code>Ctrl + 6</code></strong></td><td style="text-align:left;"><strong>开始标记文本</strong>：移动光标选中区域，选中后可用 <code>Ctrl + K</code> 剪切</td></tr><tr><td style="text-align:left;"><strong>查找</strong></td><td style="text-align:left;"><code>Ctrl + W</code></td><td style="text-align:left;">在文件中搜索关键词</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Alt + W</code></td><td style="text-align:left;">查找下一个匹配项（重复上一次搜索）</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Ctrl + \\</code></td><td style="text-align:left;">查找并替换文本</td></tr><tr><td style="text-align:left;"><strong>定位</strong></td><td style="text-align:left;"><code>Ctrl + C</code></td><td style="text-align:left;">显示当前光标所在的行列位置</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Ctrl + _</code></td><td style="text-align:left;">跳转到指定行号</td></tr><tr><td style="text-align:left;"><strong>撤销/重做</strong></td><td style="text-align:left;"><code>Alt + U</code></td><td style="text-align:left;">撤销上一步操作</td></tr><tr><td style="text-align:left;"></td><td style="text-align:left;"><code>Alt + E</code></td><td style="text-align:left;">重做撤销的操作</td></tr></tbody></table><h2 id="_5-进阶技巧与实用方法" tabindex="-1">5. 进阶技巧与实用方法 <a class="header-anchor" href="#_5-进阶技巧与实用方法" aria-label="Permalink to “5. 进阶技巧与实用方法”">​</a></h2><h3 id="_5-1-显示行号" tabindex="-1">5.1 显示行号 <a class="header-anchor" href="#_5-1-显示行号" aria-label="Permalink to “5.1 显示行号”">​</a></h3><p>编辑配置文件或代码时，显示行号非常方便。</p><ul><li><strong>临时开启</strong>：启动时加参数 <code>-l</code>。<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nano</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_file.txt</span></span></code></pre></div></li><li><strong>永久开启</strong>：编辑 Nano 的配置文件 <code>~/.nanorc</code>，添加一行 <code>set linenumbers</code>。修改后重启 Nano 生效 。</li></ul><h3 id="_5-2-语法高亮" tabindex="-1">5.2 语法高亮 <a class="header-anchor" href="#_5-2-语法高亮" aria-label="Permalink to “5.2 语法高亮”">​</a></h3><p>Nano 支持编程语言的语法高亮。可以使用 <code>-Y</code> 参数指定语言类型，例如编辑 Python 文件时启用高亮：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nano</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> script.py</span></span></code></pre></div><p>也可以将常用的配置写入 <code>~/.nanorc</code> 中，例如启用所有支持的高亮并设置 Tab 为 4 个空格 ：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/usr/share/nano/*.nanorc&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tabsize</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tabstospaces</span></span></code></pre></div><h3 id="_5-3-使用-sudo-编辑系统文件" tabindex="-1">5.3 使用 <code>sudo</code> 编辑系统文件 <a class="header-anchor" href="#_5-3-使用-sudo-编辑系统文件" aria-label="Permalink to “5.3 使用 sudo 编辑系统文件”">​</a></h3><p>当需要修改 <code>/etc/</code> 目录下的系统配置文件（如修改软件源、网络配置）时，必须拥有 root 权限。请使用 <code>sudo</code> 打开 Nano：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/apt/sources.list</span></span></code></pre></div><p>如果不慎使用了普通权限打开并编辑了无法保存，可以使用 <code>Ctrl + X</code> 退出，然后重新运行上述带 <code>sudo</code> 的命令。</p>`,35)])])}const k=e(i,[["render",n]]);export{p as __pageData,k as default};
